function uuid(){const c=globalThis.crypto;if(c?.randomUUID)return c.randomUUID();const a=new Uint8Array(16);c?.getRandomValues?.(a);a[6]=a[6]&15|64;a[8]=a[8]&63|128;return [...a].map((b,i)=>([4,6,8,10].includes(i)?'-':'')+b.toString(16).padStart(2,'0')).join('')}
function consent(){return {...consentBlank(),...read(STORAGE_KEYS.RESEARCH_CONSENT,{})}}
