async function getApi(path,token){if(!apiReady())throw new Error('api_unconfigured');const r=await fetch(`${apiBase()}${path}`,{headers:{Authorization:`Bearer ${token}`}});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(data?.error||'request_failed');return data}
