checkinFields[5]=['cycleStatus','今天妳主观感受到的周期相关状态？',['没有明显周期影响','正在出血','经前疲劳 / PMS 明显','腹胀 / 水肿','情绪波动明显','周期不规律 / 不确定','不适用']];
function getSyncMode(){return apiReady()?'cloud-ready':'local-demo'}
function syncStatusText(){return apiReady()?'匿名测试同步已启用：只会上传妳明确允许的数据':'本机演示模式：数据只保存在妳的浏览器'}
function syncSaveTipOnConsentSaved(){if(!apiReady())return tip('授权设置已保存在本机。当前演示环境未开启匿名同步，测试团队暂时不会收到妳的数据。');tip('授权设置已保存，匿名测试同步已开启。')}
function syncFailureTip(){tip('授权设置已保存在本机，但匿名同步暂时失败。妳可以稍后再试。')}
function syncTip(){if(!apiReady())tip('当前为本机演示模式，数据已保存在妳的浏览器。');else tip('已保存在本机，但匿名同步暂时失败。')}
function fireSync(promiseFactoryOrPromise,quiet=true){if(!apiReady())return;const p=typeof promiseFactoryOrPromise==='function'?promiseFactoryOrPromise():promiseFactoryOrPromise;Promise.resolve(p).catch(err=>{console.warn('[nvxun sync failed]',err);if(!quiet)syncFailureTip()})}
function syncConsent(){if(!apiReady())return Promise.resolve({mode:'local-demo'});const c=consent();if(!c.participantId)return Promise.resolve();return postApi('/v1/consent',{participantId:c.participantId,consentVersion:c.version,anonymousAnalytics:c.anonymousAnalytics,anonymousTrainingFeedback:c.anonymousTrainingFeedback,cycleAggregate:c.cycleAggregate,updatedDate:today()})}
function phaseForUpload(result){const c=consent();if(!c.cycleAggregate)return null;const phase=result&&result.cycleEstimate&&result.cycleEstimate.phaseKey||result&&result.phase&&result.phase.phaseKey||result&&result.phase&&result.phase.current_phase;return ['menstrual','follicular','ovulation','luteal','premenstrual','unknown'].includes(phase)?phase:null}
function syncTrainingFeedback(log,w,result){if(!apiReady())return Promise.resolve({mode:'local-demo'});const c=consent();if(!c.anonymousTrainingFeedback||!c.participantId)return Promise.resolve();const payload={participantId:c.participantId,consentVersion:c.version,submittedDate:today(),completion:log.completion,afterFeeling:log.afterFeeling,recommendationAccuracy:log.recommendationAccuracy,dayType:result&&result.dayType||'',workoutType:w.typeLabel||w.type},phase=phaseForUpload(result);if(phase)payload.cyclePhase=phase;return postApi('/v1/training-feedback',payload)}
function syncProductFeedback(item){if(!apiReady())return Promise.resolve({mode:'local-demo'});const c=consent();if(!item.shareText||!c.participantId)return Promise.resolve();return postApi('/v1/product-feedback',{participantId:c.participantId,consentVersion:c.version,submittedDate:today(),feedbackType:item.type,satisfaction:Number(item.satisfaction),text:item.text.trim(),textConsent:true})}
function needsCycleProfile(profile){const bs=profile&&profile.bodyStage,arr=Array.isArray(bs)?bs:(bs?[bs]:[]);return arr.some(s=>['有规律月经','有月经，但不太规律','经前反应明显'].includes(s))}
function hasCycleProfile(){const cp=read(STORAGE_KEYS.CYCLE_PROFILE,null);return !!(cp&&cp.lastPeriodStartDate&&cp.averageCycleLength&&cp.averagePeriodLength)}
function cycleProfile(){return read(STORAGE_KEYS.CYCLE_PROFILE,null)}
function cleanCycleDates(value){return [...new Set((Array.isArray(value)?value:String(value||'').split(/[\n,，\s]+/)).map(x=>String(x).trim()).filter(x=>/^\d{4}-\d{2}-\d{2}$/.test(x)&&x<=today()))].sort()}
function estimateCyclePhaseFromProfile(cycleProfileValue,refDate=today(),profile=read(STORAGE_KEYS.USER_PROFILE,{})){
 const unknown={cycleDay:null,phaseKey:'unknown',phase:'不确定',phaseLabel:'周期信息不足',confidence:'低',explanation:'目前周期信息不足，暂不强行判断周期阶段。今天会主要根据睡眠、疼痛、精力和训练意愿给出建议。',trainingHint:'先按今日状态训练即可。',daysToNextPeriod:null,source:'none'};
 const notApplicable={cycleDay:null,phaseKey:'not_applicable',phase:'不适用',phaseLabel:'当前不使用周期推算',confidence:'不适用',explanation:'当前不使用月经周期推算，将主要根据今日状态给出建议。',trainingHint:'关注睡眠、疼痛、精力和训练意愿即可。',daysToNextPeriod:null,source:'profile'};
 let cp=cycleProfileValue;
 if(!cp){const model=cycleModel();if(model.last_start_date)cp={lastPeriodStartDate:model.last_start_date,averageCycleLength:model.cycle_length_days,averagePeriodLength:model.period_length_days,regularity:model.status==='stable'?'比较规律':'有点波动',periodStartDates:model.recent.map(x=>x.start_date),source:'calendar'};else return needsCycleProfile(profile)?unknown:notApplicable}
 const dates=cleanCycleDates(cp.periodStartDates),start=cp.lastPeriodStartDate||dates.at(-1),period=Math.max(2,Math.min(10,Number(cp.averagePeriodLength)||5));let length=Math.max(21,Math.min(45,Number(cp.averageCycleLength)||28));
 if(!start||start>refDate)return unknown;
 const gaps=[];for(let i=1;i<dates.length;i++){const gap=daysBetween(dates[i-1],dates[i]);if(gap>=21&&gap<=45)gaps.push(gap)}
 let confidence='低';if(gaps.length>=2){length=Math.round(gaps.reduce((a,b)=>a+b,0)/gaps.length);const spread=Math.max(...gaps)-Math.min(...gaps);confidence=spread<=3?'高':spread<=7?'中':'低'}else if(['比较规律','有点波动'].includes(cp.regularity))confidence='中';
 const elapsed=daysBetween(start,refDate);if(!Number.isFinite(elapsed)||elapsed<0)return unknown;const cycleDay=elapsed%length+1,daysToNextPeriod=length-cycleDay,ovulationDay=Math.max(period+2,length-14);let phaseKey='luteal';
 if(cycleDay<=period)phaseKey='menstrual';else if(cycleDay<ovulationDay-2)phaseKey='follicular';else if(cycleDay<=ovulationDay+2)phaseKey='ovulation';else if(daysToNextPeriod<=5)phaseKey='premenstrual';
 const info={menstrual:{phase:'月经期',label:'预计月经期',explanation:'基于妳填写的信息推算，妳当前大致处于月经期。出血、疼痛、疲劳或想休息都很常见，今天训练更需要看疼痛和精力，不需要硬扛。',hint:'如果疼痛明显，优先恢复；状态尚可时可选轻力量、拉伸或散步。'},follicular:{phase:'卵泡期',label:'预计卵泡期',explanation:'基于妳填写的信息推算，妳当前大致处于卵泡期。很多人在这一阶段精力和训练状态更稳定，适合安排力量训练或技术练习。',hint:'如果今天睡眠和精力也不错，可以做常规或偏高质量训练。'},ovulation:{phase:'排卵窗口',label:'预计排卵窗口',explanation:'基于妳填写的信息推算，妳当前可能接近排卵窗口。状态好时可以正常训练；如果有关节不适或疲劳，建议加强热身和动作控制。',hint:'今天可以训练，但动作质量和关节稳定优先。'},luteal:{phase:'黄体期',label:'预计黄体期',explanation:'基于妳填写的信息推算，妳当前大致处于黄体期。部分人会感到恢复变慢、疲劳或情绪波动，训练时更需要关注恢复、补水和强度调整。',hint:'如果今天状态好，可以正常训练；如果疲劳或睡眠差，建议降低强度。'},premenstrual:{phase:'经前期',label:'预计经前期',explanation:'基于妳填写的信息推算，妳当前可能接近经前期。经前疲劳、睡眠变差、情绪波动、腹胀或食欲变化都很常见，今天可以把训练目标从突破改成维持或恢复。',hint:'如果今天睡眠差、压力大或疼痛明显，建议降载或恢复。'}}[phaseKey];
 return {cycleDay,phaseKey,phase:info.phase,phaseLabel:info.label,confidence,explanation:info.explanation,trainingHint:info.hint,daysToNextPeriod,daysToNext:daysToNextPeriod,averageCycleLength:length,averagePeriodLength:period,source:cp.source||'profile',current_phase:phaseKey};
}
function estimateCyclePhase(profile){return estimateCyclePhaseFromProfile(cycleProfile(),today(),profile||read(STORAGE_KEYS.USER_PROFILE,{}))}
function calculateRecommendation(input,legacyProfile={}){
 const data=input&&input.checkin?input:{checkin:input||{},profile:legacyProfile||{},cycleProfile:cycleProfile()},c=data.checkin||{},profile=data.profile||{},estimate=estimateCyclePhaseFromProfile(data.cycleProfile,today(),profile);
 let score=5;const weights={sleep:{'好':2,'一般':0,'差':-2},energy:{'高':2,'中':0,'低':-2},pain:{'无':1,'轻微':-1,'明显':-3},soreness:{'无':1,'轻微':-1,'明显':-3},stressMood:{'稳定':1,'有点压力':-1,'压力很大 / 情绪波动明显':-2},trainingIntent:{'很想练':2,'可以练':1,'不太想练':-1,'只想轻轻动一下':-2},cycleStatus:{'没有明显周期影响':0,'正在出血':-1,'经前疲劳 / PMS 明显':-2,'腹胀 / 水肿':-1,'情绪波动明显':-1,'周期不规律 / 不确定':0,'不适用':0}};
 Object.keys(weights).forEach(k=>score+=(weights[k][c[k]]||0));score+=({menstrual:-1,follicular:1,ovulation:0,luteal:-1,premenstrual:-2,unknown:0,not_applicable:0}[estimate.phaseKey]||0);let dayType=score>=9?'冲刺日':score>=6?'常规日':score>=3?'降载日':'恢复日';
 if(c.pain==='明显')dayType='恢复日';else if(estimate.phaseKey==='menstrual'&&c.pain!=='无')dayType='恢复日';else if(estimate.phaseKey==='premenstrual'&&c.sleep==='差'&&c.energy==='低')dayType=score<=1?'恢复日':'降载日';else if(estimate.phaseKey==='luteal'&&c.stressMood==='压力很大 / 情绪波动明显'&&['不太想练','只想轻轻动一下'].includes(c.trainingIntent))dayType='降载日';else if(estimate.phaseKey==='ovulation'&&c.soreness==='明显')dayType='降载日';
 if(regular(profile)&&c.sleep==='好'&&c.energy==='高'&&c.pain==='无'&&estimate.phaseKey==='follicular'&&['降载日','恢复日'].includes(dayType))dayType='常规日';
 const subjectiveMap={'正在出血':'menstrual','经前疲劳 / PMS 明显':'premenstrual'};const subjectiveConflict=!!(subjectiveMap[c.cycleStatus]&&estimate.phaseKey!==subjectiveMap[c.cycleStatus]&&['unknown','not_applicable'].includes(estimate.phaseKey)===false);
 return {score,dayType,copy:copy[dayType],phase:estimate,cycleEstimate:estimate,subjectiveConflict};
}
function cycleCard(p){const phase=p||estimateCyclePhase();const day=phase.cycleDay?'预计周期第 '+phase.cycleDay+' 天':'当前不显示周期天数';const next=Number.isFinite(phase.daysToNextPeriod)?'距离预计下次月经还有 '+phase.daysToNextPeriod+' 天':'主要根据今日状态给出建议';return '<section class="cycle-card cycle-estimate-card"><div class="cycle-card-heading"><div><p class="eyebrow">YOUR CYCLE NOTE</p><h2>'+esc(phase.phaseLabel)+'</h2></div><span class="cycle-day">'+esc(phase.confidence)+'</span></div><figure class="cycle-card-visual"><img class="cycle-ring-image" src="'+RING_IMG+'" alt="月经周期阶段示意环图"></figure><p><strong>'+esc(day)+'</strong><br>'+esc(phase.explanation)+'</p><small>'+esc(next)+' · '+esc(phase.trainingHint)+'</small></section>'}
function reasons(profile,c,result){const phase=result.cycleEstimate||result.phase,items=['周期提示：'+phase.phaseLabel,'睡眠：'+(c.sleep||'未填写'),'精力：'+(c.energy||'未填写'),'训练基础：'+(profile.trainingLevel||'以安全入门为主')];if(c.pain&&c.pain!=='无')items.push('疼痛/不适：'+c.pain);if(c.soreness&&c.soreness!=='无')items.push('肌肉或关节感受：'+c.soreness);if(c.stressMood)items.push('压力状态：'+c.stressMood);if(c.trainingIntent)items.push('训练意愿：'+c.trainingIntent);const goal=(profile.goals||[]).slice(0,2).join('、');if(goal)items.push('训练目标：'+goal);const note=result.subjectiveConflict?'妳的主观感受和周期推算可能不完全一致。今天我们优先尊重妳的身体感受，把训练建议调轻一些。 ':'';return note+'今天的安排综合了'+items.slice(0,5).join('；')+'。'+phase.trainingHint}
function profile(){shell(header('home')+'<p class="eyebrow">YOUR TRAINING CONTEXT</p><h1 class="page-title">让建议从妳的<br>真实训练起点出发。</h1><p class="form-intro">训练水平、场景和目标会改变今天推荐的训练内容。信息只保存在当前浏览器。</p><form id="profile-form">'+profileFields.map(f=>field(f,state.profile,'profile')).join('')+'<button class="button button-primary">保存并继续</button></form>')}
function cycleSetup(){const cp=cycleProfile()||{},starts=cleanCycleDates(cp.periodStartDates||[]).join('\n'),reg=cp.regularity||'比较规律';shell(header('checkin')+'<p class="eyebrow">CYCLE PROFILE · 月经周期档案</p><h1 class="page-title">先了解妳的周期，<br>再决定今天怎么练。</h1><p class="form-intro">女训不会判断妳的真实激素水平，只会基于妳填写的经期信息，推算妳当前大致处在哪个周期阶段，用于训练建议参考。</p><form id="cycle-setup-form" class="section-panel cycle-setup-form"><label class="input-field">末次月经开始日期<span>最近一次月经第一天。</span><input name="lastPeriodStartDate" type="date" required value="'+esc(cp.lastPeriodStartDate||'')+'"></label><label class="input-field">最近半年的平均周期长度<span>从一次月经开始，到下一次月经开始，通常间隔多少天？</span><input name="averageCycleLength" type="number" min="21" max="45" required value="'+esc(cp.averageCycleLength||28)+'"></label><label class="input-field">最近半年的平均经期长度<span>通常出血持续多少天？</span><input name="averagePeriodLength" type="number" min="2" max="10" required value="'+esc(cp.averagePeriodLength||5)+'"></label><label class="input-field">最近半年周期规律程度<select name="regularity"><option '+(reg==='比较规律'?'selected':'')+'>比较规律</option><option '+(reg==='有点波动'?'selected':'')+'>有点波动</option><option '+(reg==='很不规律'?'selected':'')+'>很不规律</option><option '+(reg==='不确定'?'selected':'')+'>不确定</option></select></label><label class="input-field">最近半年经期开始日期（可选）<span>可用空格、逗号或换行分隔；我们会用它估算平均周期，不记得也可以留空。</span><textarea name="periodStartDates" rows="4" placeholder="2026-01-03&#10;2026-02-01&#10;2026-03-02">'+esc(starts)+'</textarea></label><button class="button button-primary">保存周期信息，进入今日打卡</button></form>')}
function saveCycleProfile(form){const e=form.elements,start=String(e.lastPeriodStartDate.value||'');const length=Number(e.averageCycleLength.value),period=Number(e.averagePeriodLength.value);if(!/^\d{4}-\d{2}-\d{2}$/.test(start)||start>today())return tip('请填写不晚于今天的末次月经开始日期');if(length<21||length>45)return tip('平均周期长度请填写 21—45 天');if(period<2||period>10)return tip('平均经期长度请填写 2—10 天');let dates=cleanCycleDates(e.periodStartDates.value);dates=[...new Set([start,...dates])].sort();const gaps=[];for(let i=1;i<dates.length;i++){const gap=daysBetween(dates[i-1],dates[i]);if(gap>=21&&gap<=45)gaps.push(gap)}const inferred=gaps.length>=2?Math.round(gaps.reduce((a,b)=>a+b,0)/gaps.length):length;const cp={lastPeriodStartDate:start,averageCycleLength:inferred,averagePeriodLength:period,regularity:e.regularity.value,periodStartDates:dates,updatedAt:now()};save(STORAGE_KEYS.CYCLE_PROFILE,cp);const marked=new Set(menstruationDays());dates.forEach(date=>rangeDays(date,addDays(date,period-1)).forEach(day=>marked.add(day)));saveMenstruationDays([...marked]);eventLog('cycle.profile.completed');state.screen='checkin';tip('周期信息已保存在本机，接下来看看今天适合怎么练。');render()}
function checkin(){const p=read(STORAGE_KEYS.USER_PROFILE,null);if(!p){state.screen='profile';return render()}if(needsCycleProfile(p)&&!hasCycleProfile()){state.screen='cycle-setup';return render()}shell(header()+'<p class="eyebrow">1 MINUTE CHECK-IN · '+dateLabel(today())+'</p><h1 class="page-title">今天的妳，<br>状态如何？</h1><p class="form-intro">没有正确答案。按妳此刻最真实的感觉选择。周期档案用于系统推算；这一题记录的是妳的主观感受。</p><form id="checkin-form">'+checkinFields.map(f=>field(f,state.checkin,'checkin')).join('')+'<button class="button button-primary">生成今日训练建议</button></form>')}
function saveProfile(form){captureProfile(form);if(!valid(profileFields,state.profile))return;const p={...state.profile,activityLevel:state.profile.trainingLevel,createdAt:read(STORAGE_KEYS.USER_PROFILE,{}).createdAt||now(),updatedAt:now()};save(STORAGE_KEYS.USER_PROFILE,p);state.profile=p;eventLog('profile.saved','0.3 training context saved');state.screen=needsCycleProfile(p)&&!hasCycleProfile()?'cycle-setup':'checkin';tip(state.screen==='cycle-setup'?'基础设置已保存。先补充周期信息，再进入今日打卡。':'基础设置已保存在本机');render()}
function saveCheckin(){if(!valid(checkinFields,state.checkin))return;const profile=read(STORAGE_KEYS.USER_PROFILE,{}),cp=cycleProfile();if(needsCycleProfile(profile)&&!hasCycleProfile()){tip('先补充周期信息，我们才能把训练建议和妳的周期关联起来。');state.screen='cycle-setup';return render()}const recommendation=calculateRecommendation({checkin:state.checkin,profile,cycleProfile:cp}),estimate=recommendation.cycleEstimate,x={date:today(),...state.checkin,score:recommendation.score,dayType:recommendation.dayType,phaseKey:estimate.phaseKey,phaseLabel:estimate.phaseLabel,createdAt:now()},items=read(STORAGE_KEYS.DAILY_CHECKINS,[]).filter(i=>i.date!==x.date);items.unshift(x);save(STORAGE_KEYS.DAILY_CHECKINS,items);const planWorkouts=chooseWorkouts(profile,recommendation);state.last={...recommendation,workouts:planWorkouts,checkin:x};saveTodayPlan(recommendation,x,planWorkouts);eventLog('checkin.completed');eventLog('recommendation.created',recommendation.dayType+' · '+estimate.phaseKey);state.screen='result';render()}
function result(){let saved=state.last||hydrateTodayPlan(loadTodayPlan());if(!saved){const fallback=latest();if(fallback){saved=fallback;if(fallback.checkin&&fallback.checkin.date===today())saveTodayPlan(fallback,fallback.checkin,fallback.workouts)}}if(!saved){state.screen='checkin';return render()}state.last=saved;const p=read(STORAGE_KEYS.USER_PROFILE,{}),r={...saved,cycleEstimate:saved.cycleEstimate||saved.phase},selected=r.workouts||chooseWorkouts(p,r),c=r.copy||copy[r.dayType];shell(header()+'<p class="eyebrow">YOUR TRAINING DECISION</p><section class="result-hero '+(c.tone==='recovery'?'recovery':c.tone==='deload'?'deload':'')+'"><span class="result-score">状态评分 '+r.score+' / 15+</span><h1>'+esc(c.title)+'</h1><p>'+esc(c.explain)+'</p></section>'+cycleCard(r.cycleEstimate)+'<section class="section-panel"><p class="eyebrow">WHY THIS TODAY</p><h2 class="section-title">为什么今天这样推荐？</h2><p class="body-copy">'+esc(reasons(p,r.checkin,r))+'</p></section><p class="recommendation-copy"><strong>今天怎么练：</strong>'+esc(c.advice)+'</p><div class="section-head"><h2 class="section-title">选一个现在做得到的</h2><span class="tiny">根据妳的水平与场景</span></div><div class="workout-grid">'+selected.map(workoutCardCompact).join('')+'</div>'+'<div class="callout '+(r.dayType==='恢复日'?'warning':'')+'"><strong>给今天的妳：</strong>'+esc(c.encourage)+(r.checkin.pain==='明显'?'<br><strong>安全提醒：</strong>明显疼痛或异常不适时，请停止训练并在需要时咨询医生。':'')+'</div><button class="button button-quiet redo-checkin" data-action="redo-checkin">重新评估今天的状态</button><button class="button button-secondary feedback-entry" data-action="go" data-screen="product-feedback">这个建议贴合妳今天的状态吗？反馈一下</button>')}
function privacy(){const c=consent(),local=getSyncMode()==='local-demo',status=local?'当前为本机演示模式':'匿名测试同步可用',description=local?'数据只保存在妳的浏览器。妳仍然可以完整试用女训，测试团队暂时不会收到妳的数据。':'只有妳主动开启并授权的数据，才会匿名提交给测试团队。';shell(header()+'<p class="eyebrow">PRIVACY & TEST DATA</p><h1 class="page-title">妳的数据，<br>由妳决定。</h1><p class="form-intro">女训默认只在妳的设备上保存记录。只有当妳主动开启匿名测试同步时，我们才会收到被允许的数据，用来改进训练体验。</p><section class="privacy-status"><strong>'+status+'</strong><span>'+description+'</span><small>'+syncStatusText()+'。测试数据仅用于改进女训，不用于广告、营销或个人画像。</small></section><form id="privacy-consent-form" class="privacy-consent"><h2 class="section-title">匿名测试授权</h2>'+consentToggle('anonymousAnalytics','匿名使用体验数据','帮助我们了解大家在哪些环节更容易卡住，例如是否完成了设置、是否生成训练推荐。不会上传姓名、联系方式、原始身体记录或经期日期。',c.anonymousAnalytics)+consentToggle('anonymousTrainingFeedback','匿名训练反馈','帮助我们评估推荐是否合适。仅上传训练是否完成、训练后感觉、推荐准确度等选项结果。不会上传力量训练重量、组数、次数或备注。',c.anonymousTrainingFeedback)+consentToggle('cycleAggregate','周期阶段汇总','只上传预测阶段的匿名汇总，例如月经期、卵泡期、排卵窗口、黄体期、经前期或不确定；不会上传具体日期、经期区间或可反推出日期的信息。',c.cycleAggregate)+'<button class="button button-primary">保存授权设置</button></form><section class="detail-card privacy-actions"><h2 class="section-title">帮助我们改进女训</h2><p>妳可以单独提交一条体验反馈。文字内容默认只保存在本机，只有妳在那一条反馈里单独勾选授权时才会匿名上传。</p><button class="button button-secondary" data-action="go" data-screen="product-feedback">提交体验反馈</button></section><section class="detail-card privacy-actions"><h2 class="section-title">停止与删除</h2><p>关闭授权后，后续不再上传；已上传的数据需点击删除按钮才会请求删除。</p><button class="button button-secondary" data-action="delete-cloud-data">删除已上传的测试数据</button><button class="button button-danger" data-action="clear-data">清除本机全部数据</button></section><div class="callout"><strong>我们不会收集：</strong>姓名、手机号、邮箱、精确位置、身份信息、原始经期日期、经期区间、身体围度、体重、力量训练详细重量，也不接广告 SDK、第三方埋点 SDK 或 AI API。</div>')}
function saveConsentForm(form){const e=form.elements,before=consent(),next={...before,anonymousAnalytics:!!e.anonymousAnalytics.checked,anonymousTrainingFeedback:!!e.anonymousTrainingFeedback.checked,cycleAggregate:!!e.cycleAggregate.checked};saveConsentState(next);const c=consent(),shouldTryCloud=apiReady()&&(c.anonymousAnalytics||c.anonymousTrainingFeedback||c.cycleAggregate||before.participantId);if(shouldTryCloud){fireSync(syncConsent,false);tip('授权设置已保存，正在同步匿名测试设置。')}else syncSaveTipOnConsentSaved();render()}
function productFeedback(){if(state.productFeedbackTrackedDate!==today()){state.productFeedbackTrackedDate=today();eventLog('product.feedback.opened')}const f=state.productFeedback,types=['使用问题','推荐体验','功能建议','内容建议','其她'];shell(header('privacy')+'<p class="eyebrow">HELP US IMPROVE</p><h1 class="page-title">妳的感受，<br>会让女训更贴近真实生活。</h1><p class="form-intro">这里不需要姓名、手机号、邮箱或登录。文字反馈默认只保存在本机。</p><form id="product-feedback-form" class="product-feedback-form"><fieldset class="question"><legend>反馈类型</legend><div class="choice-grid two">'+types.map(v=>'<button type="button" class="choice '+(f.type===v?'selected':'')+'" data-action="product-pick" data-field="type" data-value="'+v+'"><span class="dot"></span>'+v+'</button>').join('')+'</div></fieldset><fieldset class="question"><legend>满意度</legend><div class="rating-row">'+[1,2,3,4,5].map(v=>'<button type="button" class="rating-button '+(Number(f.satisfaction)===v?'selected':'')+'" data-action="product-pick" data-field="satisfaction" data-value="'+v+'" aria-label="'+v+' 分">'+v+'</button>').join('')+'</div></fieldset><label class="input-field">文字反馈（可选）<span>最多 500 字；未单独授权时只保存在本机。</span><textarea name="productText" rows="5" maxlength="500" placeholder="例如：哪个步骤不清楚、推荐哪里不贴合、希望增加什么内容。">'+esc(f.text||'')+'</textarea></label><label class="consent-toggle product-text-consent"><input type="checkbox" name="shareText" '+(f.shareText?'checked':'')+'><span><strong>我同意将这条文字反馈匿名提交给女训测试团队，用于产品改进。</strong><small>每一条文字反馈都需要单独勾选。其她匿名授权不会自动上传文字。</small></span></label><button class="button button-primary">提交反馈</button></form>')}
function saveProductFeedback(form){captureProductFeedback(form);if(!state.productFeedback.type)return tip('请先选择反馈类型');if(!state.productFeedback.satisfaction)return tip('请先选择满意度');const item={id:'pf-'+Date.now(),date:today(),type:state.productFeedback.type,satisfaction:Number(state.productFeedback.satisfaction),text:state.productFeedback.text||'',shareText:!!state.productFeedback.shareText,createdAt:now()},items=read(STORAGE_KEYS.PRODUCT_FEEDBACKS,[]);items.unshift(item);save(STORAGE_KEYS.PRODUCT_FEEDBACKS,items.slice(0,30));if(item.shareText&&apiReady()){const c=consent();if(!c.participantId)saveConsentState(c);fireSync(()=>syncProductFeedback(item),false);tip('反馈已保存在本机，正在同步已单独授权的文字反馈。')}else if(!apiReady())tip('当前为本机演示模式，反馈已保存在妳的浏览器。');else tip('反馈已保存在本机；未勾选文字授权时不会上传。');state.productFeedback={type:'',satisfaction:'',text:'',shareText:false};state.screen='privacy';render()}
function records(){const content=state.recordTab==='calendar'?calendarRecords():state.recordTab==='body'?bodyRecords():state.recordTab==='training'?trainingRecords():stateRecords();shell(header()+'<p class="eyebrow">YOUR BODY, YOUR PATTERN</p><h1 class="page-title">训练不是每天<br>都一样强。</h1><p class="form-intro">记录不是考核，是帮妳看见自己正在怎样调整和变强。</p>'+recordTabs()+content+'<button class="button button-secondary feedback-entry" data-action="go" data-screen="product-feedback">反馈使用体验</button>')}
function cycle(){if(state.cycleTrackedDate!==today()){eventLog('cycle.viewed');state.cycleTrackedDate=today()}const cp=cycleProfile(),estimate=estimateCyclePhaseFromProfile(cp,today(),read(STORAGE_KEYS.USER_PROFILE,{})),days=menstruationDays(),selected=new Set(days),episodes=deriveEpisodes(days),model=cycleModel(days),displayKey=['menstrual','follicular','ovulation','luteal'].includes(estimate.phaseKey)?estimate.phaseKey:estimate.phaseKey==='premenstrual'?'luteal':null,display=displayKey?PHASES[displayKey]:null,monthTitle=state.calendarMonth.replace('-','年')+'月';const profileCard=cp?'<section class="cycle-profile-summary"><div><span>末次月经开始日期</span><b>'+esc(cp.lastPeriodStartDate)+'</b></div><div><span>平均周期长度</span><b>'+esc(cp.averageCycleLength)+' 天</b></div><div><span>平均经期长度</span><b>'+esc(cp.averagePeriodLength)+' 天</b></div></section>':'<section class="callout"><strong>还没有周期档案。</strong> 妳可以先补充信息，让训练建议多一个节律参考。</section>';const analysis='<section class="cycle-health-card cycle-analysis '+(!display?'is-unknown':'')+'"><div><span class="tiny">基于妳填写的信息推算 · 仅供训练参考，不代表真实激素检测</span><h2>'+esc(estimate.phaseLabel)+'</h2><p>'+esc(estimate.explanation)+'</p></div><strong style="--phase:'+(display?display.color:'#b9abb2')+'">'+(estimate.cycleDay?'第 '+estimate.cycleDay+' 天':'--')+'</strong></section>';const metrics='<section class="cycle-metrics"><article><span>预计周期阶段</span><b>'+esc(estimate.phase)+'</b><em>可信度 '+esc(estimate.confidence)+'</em></article><article><span>距离预计下次月经</span><b>'+(Number.isFinite(estimate.daysToNextPeriod)?estimate.daysToNextPeriod:'--')+'</b><em>天</em></article><article><span>训练提示</span><b>'+esc(estimate.trainingHint)+'</b><em>以今日状态为准</em></article></section>';const calendar='<section class="cycle-calendar"><div class="calendar-head"><button class="icon-button" data-action="cycle-prev" aria-label="上个月">‹</button><strong>'+monthTitle+'</strong><button class="icon-button" data-action="cycle-next" aria-label="下个月">›</button></div><div class="week-row">'+['日','一','二','三','四','五','六'].map(x=>'<span>'+x+'</span>').join('')+'</div><div class="month-grid">'+monthDays().map(d=>{const on=selected.has(d.iso),ep=episodes.find(x=>daysBetween(x.start_date,d.iso)>=0&&daysBetween(d.iso,x.end_date)>=0),start=ep&&ep.start_date===d.iso,end=ep&&ep.end_date===d.iso;return '<button class="day-cell '+(d.inMonth?'':'muted-day ') +(on?'selected ':'')+(ep?'in-period ':'')+(start?'period-start ':'')+(end?'period-end ':'')+'" data-action="cycle-day" data-date="'+d.iso+'" aria-pressed="'+on+'"><span>'+d.day+'</span></button>'}).join('')+'</div><p class="calendar-hint">点击日期可补充经期记录。周期档案优先用于推算；日历记录会继续保存在本机。</p></section>';const ring=display?phaseWheel(displayKey,state.selectedPhase||displayKey):'';shell(header()+'<p class="eyebrow">CYCLE INSIGHT</p><h1 class="page-title">记录经期，<br>让训练更懂节律。</h1><p class="form-intro">周期阶段为基于妳填写的信息推算，仅供训练参考，不代表真实激素检测。</p>'+profileCard+'<button class="button button-secondary" data-action="go" data-screen="cycle-setup">更新周期信息</button>'+analysis+metrics+(estimate.phaseKey==='premenstrual'?'<p class="premenstrual-note">经前 5 天：在黄体期后段更重视恢复和主观感受。</p>':'')+calendar+ring+'<section class="episode-list"><h2 class="section-title">已识别经期区间</h2>'+(episodes.length?episodes.slice().reverse().slice(0,5).map(e=>'<div class="episode-row"><span>'+dateLabel(e.start_date)+' - '+dateLabel(e.end_date)+'</span><strong>'+ (daysBetween(e.start_date,e.end_date)+1)+' 天</strong></div>').join(''):'<p class="empty-small">可以继续用日历补充经期日期；记录越完整，估算越稳定。</p>')+'</section>')}
function latest(){const records=newest(read(STORAGE_KEYS.DAILY_CHECKINS,[]),'date'),checkin=records.find(x=>x.date===today())||records[0];if(!checkin)return null;const p=read(STORAGE_KEYS.USER_PROFILE,{}),r=calculateRecommendation({checkin,profile:p,cycleProfile:cycleProfile()});return {...r,score:checkin.score??r.score,dayType:checkin.dayType||r.dayType,workouts:chooseWorkouts(p,r),checkin}}
function render(){if(state.mode==='admin'){admin();return wireRingFallback()}const f={welcome,profile,'cycle-setup':cycleSetup,checkin,result,workout,feedback,cycle,records,library,action:movement,videos:videoLibrary,privacy,productFeedback,'product-feedback':productFeedback}[state.screen]||welcome;f();wireRingFallback()}

