function eventLog(type,detail='',level='info'){const events=read(STORAGE_KEYS.EVENTS,[]);events.unshift({id:'evt-'+Date.now(),at:now(),type,detail,level});save(STORAGE_KEYS.EVENTS,events.slice(0,80));const eventType=EVENT_UPLOAD_MAP[type],c=consent();if(eventType&&c.anonymousAnalytics&&c.participantId&&apiReady())fireSync(()=>postApi('/v1/event',{participantId:c.participantId,consentVersion:c.version,eventType,eventDate:today()}))}

