function adminOverview(){const s=state.adminSummary||{},o=s.overview||{};return '<p class="eyebrow">ANONYMOUS TESTING</p><h1 class="page-title">匿名测试数据概览</h1><section class="dashboard-grid">'+metric('已授权匿名参与者',o.participants)+metric('匿名使用事件数量',o.analyticsEvents)+metric('训练反馈数量',o.trainingFeedback)+metric('产品反馈数量',o.productFeedback)+metric('近 7 天活跃',o.active7)+metric('近 30 天活跃',o.active30)+metric('使用体验授权人数',o.analyticsConsent)+metric('训练反馈授权人数',o.trainingConsent)+metric('周期汇总授权人数',o.cycleConsent)+'</section>'}
function adminCycle(){const s=state.adminSummary&&state.adminSummary.cycle||{},labels={menstrual:'月经期',follicular:'卵泡期',ovulation:'排卵窗口',luteal:'黄体期',premenstrual:'经前期',unknown:'不确定'},named=items=>(items||[]).map(x=>{const parts=String(x.label||x.key||'').split(' · ');return {...x,label:(labels[parts[0]]||parts[0])+(parts[1]?' · '+parts[1]:'')}});return '<p class="eyebrow">CYCLE AGGREGATE</p><h1 class="page-title">周期阶段汇总</h1><div class="callout">仅统计已授权匿名阶段汇总，不包含原始经期日期、周期天数或个人记录。</div><section class="admin-card"><h2>阶段匿名数量</h2>'+bars(named(s.phaseCounts))+'</section><section class="admin-card"><h2>各阶段训练完成情况</h2>'+bars(named(s.completionByPhase))+'</section><section class="admin-card"><h2>各阶段推荐准确度</h2>'+bars(named(s.accuracyByPhase))+'</section>'}

