/* NVXUN_V05 — 今日方案固定常驻：当天生成后持久化到本机，跳转/刷新都不重新计算或重新随机 */
STORAGE_KEYS.TODAY_PLAN='nvxun_todayPlanV1';
function workoutById(id){return workoutLibraryV2.find(w=>w.id===id)}
function saveTodayPlan(recommendation,checkin,workouts){const est=(recommendation&&(recommendation.cycleEstimate||recommendation.phase))||{};const plan={version:1,date:today(),createdAt:now(),checkin:checkin||{},score:recommendation.score,dayType:recommendation.dayType,copyKey:recommendation.dayType,phase:est,cycleEstimate:est,subjectiveConflict:!!recommendation.subjectiveConflict,workoutIds:(workouts||[]).map(w=>w&&w.id).filter(Boolean)};save(STORAGE_KEYS.TODAY_PLAN,plan);return plan}
function loadTodayPlan(){const plan=read(STORAGE_KEYS.TODAY_PLAN,null);if(!plan||plan.version!==1||plan.date!==today())return null;return plan}
function hydrateTodayPlan(plan){if(!plan)return null;const est=plan.cycleEstimate||plan.phase||{};let workouts=(Array.isArray(plan.workoutIds)?plan.workoutIds:[]).map(workoutById).filter(Boolean);if(!workouts.length)workouts=chooseWorkouts(read(STORAGE_KEYS.USER_PROFILE,{}),{dayType:plan.dayType,phase:est,cycleEstimate:est});return {score:plan.score,dayType:plan.dayType,copy:copy[plan.copyKey]||copy[plan.dayType],phase:est,cycleEstimate:est,subjectiveConflict:!!plan.subjectiveConflict,workouts,checkin:plan.checkin||{}}}
