 if(a==='open-strength-log'){state.screen='strength-log';render()}
 if(a==='strength-add-row'){captureStrengthDraft();state.strengthDraft.exercises.push(blankStrengthRow());render()}
 if(a==='strength-remove-row'){captureStrengthDraft();state.strengthDraft.exercises.splice(Number(b.dataset.index),1);if(!state.strengthDraft.exercises.length)state.strengthDraft.exercises.push(blankStrengthRow());render()}
 if(a==='strength-recalc'){captureStrengthDraft();render()}
